"""
T2 RBAC System — Auth Routes (Sample 2 / Gen 1)

Login endpoint with an inline, try/except-driven approach.

Differences from Sample 1:
- Uses request.json directly (no silent mode), catches JSON parse errors via try/except
- Validation and DB query logic inlined inside the route handler (no helper extraction)
- Expiry computed with calendar.timegm() + datetime.datetime.utcnow() for a Unix timestamp
- Error message format uses a single 'reason' field inside the 'error' dict
"""

import calendar
import datetime

import jwt as pyjwt
from flask import Blueprint, request, jsonify, current_app

from models import User
from middleware import hash_password
from app import db

auth_bp = Blueprint('auth_bp', __name__)


@auth_bp.route('/login', methods=['POST'])
def login():
    """Authenticate a user and return a signed JWT.

    Request body: {"username": str, "password": str}
    Success response: {"status": "ok", "data": {"token": "<jwt>"}}
    """
    # --- Parse JSON body (let Flask raise on invalid content-type) ---
    try:
        body = request.json
    except Exception:
        return jsonify({
            'status': 'error',
            'message': 'Request body must be valid JSON',
        }), 400

    # --- Validate required fields ---
    username = (body or {}).get('username')
    password = (body or {}).get('password')

    if not username:
        return jsonify({
            'status': 'error',
            'message': 'Missing required field: username',
        }), 400

    if not password:
        return jsonify({
            'status': 'error',
            'message': 'Missing required field: password',
        }), 400

    # --- Lookup user ---
    user = User.query.filter_by(username=username).first()

    if user is None:
        return jsonify({
            'status': 'error',
            'message': 'Authentication failed',
        }), 401

    # --- Verify password ---
    if user.password_hash != hash_password(password):
        return jsonify({
            'status': 'error',
            'message': 'Authentication failed',
        }), 401

    # --- Build JWT ---
    now = datetime.datetime.utcnow()
    expiry_hours = current_app.config.get('JWT_EXPIRY_HOURS', 24)
    exp_timestamp = calendar.timegm(
        (now + datetime.timedelta(hours=expiry_hours)).timetuple()
    )

    secret = current_app.config.get('JWT_SECRET', 'dev-secret-key')
    token = pyjwt.encode(
        {
            'user_id': user.id,
            'tenant_id': user.tenant_id,
            'exp': exp_timestamp,
        },
        secret,
        algorithm='HS256',
    )

    return jsonify({
        'status': 'ok',
        'data': {'token': token},
    }), 200

