"""
T2 RBAC System -- Document Routes (Gen 1 Sample 2 Variant)

Evolutionary approach: inline all logic without helper extraction,
use require_auth + manual permission checks inside each route,
request.json for body parsing, and db.session.query().filter()
for tenant-scoped lookups.

Register as a Flask Blueprint named 'document_bp'.

Key design decisions (Sample 2 signature):
- require_auth decorator only handles authentication; permission
  checks are performed manually inside each route handler.
- No _serialize_document() helper -- dict construction is inline.
- No _get_document_or_404() helper -- lookup logic is repeated per route.
- request.json (not silent=True) for body access.
- PUT owner + write.any check uses nested if-else structure.
- db.session.query(Document).filter() instead of filter_by for tenant filtering.
"""

from flask import Blueprint, request, jsonify, g

from models import Document
from middleware import require_auth
from app import db

document_bp = Blueprint('document_bp', __name__)


@document_bp.route('/documents', methods=['GET'])
@require_auth
def list_documents():
    """GET /documents -- List all documents for the current user's tenant.

    Requires: doc.read permission.

    Success (200):
        {"status": "ok", "data": [{"id": int, "tenant_id": int, "owner_id": int,
                  "title": str, "content": str}, ...]}

    Errors:
        403 -- Missing doc.read permission
    """
    if 'doc.read' not in g.current_permissions:
        return jsonify({'status': 'error', 'message': 'Permission denied'}), 403

    tenant_id = g.current_user.tenant_id
    docs = db.session.query(Document).filter(Document.tenant_id == tenant_id).all()

    return jsonify({
        'status': 'ok',
        'data': [
            {
                'id': d.id,
                'tenant_id': d.tenant_id,
                'owner_id': d.owner_id,
                'title': d.title,
                'content': d.content,
            }
            for d in docs
        ],
    }), 200


@document_bp.route('/documents/<int:doc_id>', methods=['GET'])
@require_auth
def get_document(doc_id):
    """GET /documents/<id> -- Retrieve a single document by ID.

    Requires: doc.read permission + same tenant.

    Success (200):
        {"status": "ok", "data": {"id": int, "tenant_id": int, "owner_id": int,
                  "title": str, "content": str}}

    Errors:
        403 -- Missing doc.read permission
        404 -- Document not found or different tenant
    """
    if 'doc.read' not in g.current_permissions:
        return jsonify({'status': 'error', 'message': 'Permission denied'}), 403

    tenant_id = g.current_user.tenant_id
    doc = db.session.query(Document).filter(
        Document.id == doc_id,
        Document.tenant_id == tenant_id,
    ).first()

    if doc is None:
        return jsonify({'status': 'error', 'message': 'Document not found'}), 404

    return jsonify({
        'status': 'ok',
        'data': {
            'id': doc.id,
            'tenant_id': doc.tenant_id,
            'owner_id': doc.owner_id,
            'title': doc.title,
            'content': doc.content,
        },
    }), 200


@document_bp.route('/documents', methods=['POST'])
@require_auth
def create_document():
    """POST /documents -- Create a new document.

    Requires: doc.write permission.
    tenant_id is taken from the JWT; owner_id is the current user.

    Request body (JSON):
        {"title": str, "content": str}

    Success (201):
        {"status": "ok", "data": {"id": int, "tenant_id": int, "owner_id": int,
                  "title": str, "content": str}}

    Errors:
        400 -- Malformed JSON or missing title
        403 -- Missing doc.write permission
    """
    if 'doc.write' not in g.current_permissions:
        return jsonify({'status': 'error', 'message': 'Permission denied'}), 403

    body = request.json

    if not isinstance(body, dict) or 'title' not in body:
        return jsonify({'status': 'error', 'message': 'Missing title'}), 400

    title = body['title']
    content = body.get('content', '')

    doc = Document(
        tenant_id=g.current_user.tenant_id,
        owner_id=g.current_user.id,
        title=title,
        content=content,
    )
    db.session.add(doc)
    db.session.commit()

    return jsonify({
        'status': 'ok',
        'data': {
            'id': doc.id,
            'tenant_id': doc.tenant_id,
            'owner_id': doc.owner_id,
            'title': doc.title,
            'content': doc.content,
        },
    }), 201


@document_bp.route('/documents/<int:doc_id>', methods=['PUT'])
@require_auth
def update_document(doc_id):
    """PUT /documents/<id> -- Update an existing document.

    Requires: doc.write permission + (owner OR doc.write.any permission) + same tenant.

    Request body (JSON):
        {"title": str, "content": str}

    Success (200):
        {"status": "ok", "data": {"id": int, "tenant_id": int, "owner_id": int,
                  "title": str, "content": str}}

    Errors:
        400 -- Malformed JSON
        403 -- Missing doc.write, or not owner and no doc.write.any
        404 -- Document not found or different tenant
    """
    if 'doc.write' not in g.current_permissions:
        return jsonify({'status': 'error', 'message': 'Permission denied'}), 403

    tenant_id = g.current_user.tenant_id
    doc = db.session.query(Document).filter(
        Document.id == doc_id,
        Document.tenant_id == tenant_id,
    ).first()

    if doc is None:
        return jsonify({'status': 'error', 'message': 'Document not found'}), 404

    # Nested if-else: check ownership first, then fall back to write.any
    if doc.owner_id == g.current_user.id:
        pass  # Owner -- proceed with update
    else:
        if 'doc.write.any' not in g.current_permissions:
            return jsonify({'status': 'error', 'message': 'Permission denied'}), 403

    body = request.json
    if isinstance(body, dict):
        if 'title' in body:
            doc.title = body['title']
        if 'content' in body:
            doc.content = body['content']

    db.session.commit()

    return jsonify({
        'status': 'ok',
        'data': {
            'id': doc.id,
            'tenant_id': doc.tenant_id,
            'owner_id': doc.owner_id,
            'title': doc.title,
            'content': doc.content,
        },
    }), 200


@document_bp.route('/documents/<int:doc_id>', methods=['DELETE'])
@require_auth
def delete_document(doc_id):
    """DELETE /documents/<id> -- Delete a document.

    Requires: doc.delete permission + same tenant.

    Success (200):
        {"status": "ok", "data": {"message": "Document deleted"}}

    Errors:
        403 -- Missing doc.delete permission
        404 -- Document not found or different tenant
    """
    if 'doc.delete' not in g.current_permissions:
        return jsonify({'status': 'error', 'message': 'Permission denied'}), 403

    tenant_id = g.current_user.tenant_id
    doc = db.session.query(Document).filter(
        Document.id == doc_id,
        Document.tenant_id == tenant_id,
    ).first()

    if doc is None:
        return jsonify({'status': 'error', 'message': 'Document not found'}), 404

    db.session.delete(doc)
    db.session.commit()

    return jsonify({
        'status': 'ok',
        'data': {'message': 'Document deleted'},
    }), 200

